const http = require('http');
const https = require('https');
const crypto = require('crypto');
const url = require('url');
const CONFIG = { USERNAME: 'ADMIN', PASSWORD: 'IDO', META_TOKEN: process.env.META_TOKEN || '', PORT: process.env.PORT || 3000 };
const sessions = new Map();
function createSession() { const id = crypto.randomBytes(32).toString('hex'); sessions.set(id,{created:Date.now()}); setTimeout(()=>sessions.delete(id),86400000); return id; }
function isValidSession(sid) { return sessions.has(sid); }
function setCORS(res) { res.setHeader('Access-Control-Allow-Origin','*'); res.setHeader('Access-Control-Allow-Methods','GET,POST,OPTIONS'); res.setHeader('Access-Control-Allow-Headers','Content-Type,Authorization'); }
function metaProxy(path,method,body,res) {
  const sep=path.includes('?')?'&':'?';
  const options={hostname:'graph.facebook.com',path:'/v19.0/'+path+sep+'access_token='+CONFIG.META_TOKEN,method:method||'GET',headers:{'Content-Type':'application/x-www-form-urlencoded'}};
  const req=https.request(options,apiRes=>{let data='';apiRes.on('data',c=>data+=c);apiRes.on('end',()=>{setCORS(res);res.setHeader('Content-Type','application/json');res.writeHead(200);res.end(data);});});
  req.on('error',e=>{setCORS(res);res.writeHead(500);res.end(JSON.stringify({error:{message:e.message}}));});
  if(body)req.write(body);req.end();
}
